/*
 * exp() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly exp    (test_exp_opt.elf)
 *   2. Linked with toolchain's default exp         (test_exp_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += exp(vx);
#else
    double r = exp(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* test_representative_100: 100 representative inputs for exp()        */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal: -2^-1074 */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN);                  /* 2^-1022, smallest positive normal */
    emit(-DBL_MIN);
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit(DBL_MAX);                  /* 0x7fefffffffffffff, largest finite */
    emit(-DBL_MAX);
    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX itself (same as above via literal) */

    /* --- Section 4: Near 1.0 (ULP density region) (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3feffffffffffffcULL);  /* a few ULPs below 1.0 */
    emit_u(0x3ff0000000000004ULL);  /* a few ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 */
    emit_u(0x3fdffffffffffffULL);   /* one ULP below 0.5 */
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0x4000000000000000ULL);  /* 2.0 */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */

    /* --- Section 6: Exp-specific mathematical constants (14) --- */
    emit(1.0);                                       /* exp(1) = e */
    emit(-1.0);                                      /* exp(-1) = 1/e */
    emit(2.0);                                       /* exp(2) */
    emit(-2.0);                                      /* exp(-2) */
    emit(0.5);                                       /* exp(0.5) = sqrt(e) */
    emit(-0.5);                                      /* exp(-0.5) */
    emit_u(0x3fe62e42fefa39efULL);                   /* ln(2): exp = 2.0 exactly */
    emit_u(0xbfe62e42fefa39efULL);                   /* -ln(2): exp = 0.5 exactly */
    emit_u(0x40026bb1bbb55516ULL);                   /* ln(10): exp = 10.0 */
    emit_u(0xc0026bb1bbb55516ULL);                   /* -ln(10): exp = 0.1 */
    emit(0.25);                                      /* exp(0.25) */
    emit(-0.25);                                     /* exp(-0.25) */
    emit_u(0x4005bf0a8b145769ULL);                   /* e ~ 2.71828...: exp(e) */
    emit(-2.718281828459045);                        /* exp(-e) */

    /* --- Section 7: Near-zero fast-path (exp(x) ~ 1+x region) (8) --- */
    emit(1.0e-20);
    emit(-1.0e-20);
    emit(1.0e-15);
    emit(-1.0e-15);
    emit(1.0e-10);
    emit(-1.0e-10);
    emit(1.0e-5);
    emit(-1.0e-5);

    /* --- Section 8: Overflow/underflow threshold values (12) --- */
    emit_u(0x40862e42fefa39efULL);  /* exp overflow threshold: ~709.7827... */
    emit_u(0x40862e42fefa39eeULL);  /* one ULP below overflow threshold */
    emit_u(0x40862e42fefa39f0ULL);  /* one ULP above overflow threshold -> +Inf */
    emit(709.0);                    /* just below overflow */
    emit(709.5);                    /* closer to overflow */
    emit(709.78);                   /* oscillating near threshold */
    emit(-745.0);                   /* near underflow boundary */
    emit(-745.13);                  /* closer to underflow */
    emit_u(0xc0878794eca17ac6ULL);  /* exp underflow threshold: ~-745.133... */
    emit_u(0xc0878794eca17ac5ULL);  /* one ULP less negative than underflow threshold */
    emit_u(0xc0878794eca17ac7ULL);  /* one ULP more negative than underflow threshold -> 0 */
    emit(-746.0);                   /* deep underflow */

    /* --- Section 9: Mid-range representative values (14) --- */
    emit(3.0);
    emit(-3.0);
    emit(5.0);
    emit(-5.0);
    emit(0.1);
    emit(-0.1);
    emit(10.0);
    emit(-10.0);
    emit(50.0);
    emit(-50.0);
    emit(100.0);
    emit(-100.0);
    emit(700.0);
    emit(-700.0);

    /* --- Section 10: Hard cases and ln2 multiples (19) --- */
    emit_u(0x3fe62e42fefa39efULL);  /* ln2 * 1: exact bit pattern (dup section 6, different focus) */
    /* ln2 * k -> exp = 2^k, should be exact */
    emit(1.3862943611198906);       /* ln2 * 2 -> 4.0 */
    emit(2.0794415416798357);       /* ln2 * 3 -> 8.0 */
    emit(2.772588722239781);        /* ln2 * 4 -> 16.0 */
    emit(3.4657359027997265);       /* ln2 * 5 -> 32.0 */
    emit(-1.3862943611198906);      /* -ln2 * 2 -> 0.25 */
    emit(-2.0794415416798357);      /* -ln2 * 3 -> 0.125 */
    emit(-2.772588722239781);       /* -ln2 * 4 -> 0.0625 */
    emit(-3.4657359027997265);      /* -ln2 * 5 -> 0.03125 */
    emit(1.0e300);                  /* deep overflow */
    emit(-1.0e300);                 /* deep underflow -> 0 */
    emit_u(0x3cb0000000000000ULL);  /* 2^-52: near boundary of exp(x)~1+x */
    emit_u(0xbcb0000000000000ULL);  /* -2^-52 */
    emit_u(0x3c90000000000000ULL);  /* 2^-54: well inside linear region */
    emit_u(0xbc90000000000000ULL);  /* -2^-54 */
    emit(708.3964185322641);        /* ln(DBL_MAX): exp nearly reaches DBL_MAX */
    emit(-708.3964185322641);       /* exp(-ln(DBL_MAX)) = 1/DBL_MAX */
    emit(355.0);                    /* mid-large, no overflow */
    emit(-355.0);                   /* mid-large negative */
}

/* ------------------------------------------------------------------ */

/* 7. Sweep [-100, 100] in 200 steps each */
static void test_sweep(void)
{
    double hi = 100.0;
    int nsteps = 200;
    double step = (2.0 * hi) / (double)nsteps;

    /* [-100, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);

    /* [0, 100] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}

/* 8. Sample [0, 1] every 2^47 ULP (~256 cases) */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fc0000000000000ULL, /* 0.125 */
        0x3fd0000000000000ULL, /* 0.25 */
        0x3fd8000000000000ULL, /* 0.375 */
        0x3fe0000000000000ULL, /* 0.5 */
        0x3fe4000000000000ULL, /* 0.625 */
        0x3fe8000000000000ULL, /* 0.75 */
        0x3ff0000000000000ULL, /* 1.0 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i]);
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

