    emit_u(0x40862e42fefa39efULL);  /* exp overflow threshold ~ 709.782712 */
    emit_u(0x40862e42fefa39eeULL);  /* one ULP below overflow threshold */
    emit_u(0x40862e42fefa39f0ULL);  /* one ULP above overflow threshold -> +Inf */
    emit(709.0);                    /* just below overflow */
    emit(709.5);                    /* near overflow */
    emit(709.78);                   /* near threshold */
    emit_u(0xc0878794eca17ac6ULL);  /* exp underflow threshold ~ -745.1332 */
    emit_u(0xc0878794eca17ac5ULL);  /* one ULP less negative than underflow threshold */
    emit_u(0xc0878794eca17ac7ULL);  /* one ULP more negative -> rounds to 0 */
    emit(-745.0);                   /* near underflow boundary */
    emit(-745.13);                  /* closer to underflow */
    emit(-746.0);                   /* below underflow threshold -> 0 */

    /* --- Section 9: Mid-range representative values (15) --- */
    emit(3.0);
    emit(-3.0);
    emit(5.0);
    emit(-5.0);
    emit(0.1);
    emit(-0.1);
    emit(50.0);
    emit(-50.0);
    emit(100.0);
    emit(-100.0);
    emit(200.0);
    emit(-200.0);
    emit(500.0);
    emit(-500.0);
    emit(700.0);

    /* --- Section 10: Hard cases and ln2 multiples (19) --- */
    emit(-700.0);                   /* symmetric large negative */
    emit(1.3862943611198906);       /* ln2 * 2 -> exp = 4.0 exactly */
    emit(2.0794415416798357);       /* ln2 * 3 -> exp = 8.0 exactly */
    emit(2.772588722239781);        /* ln2 * 4 -> exp = 16.0 exactly */
    emit(3.4657359027997265);       /* ln2 * 5 -> exp = 32.0 exactly */
    emit(-1.3862943611198906);      /* -ln2 * 2 -> exp = 0.25 exactly */
    emit(-2.0794415416798357);      /* -ln2 * 3 -> exp = 0.125 exactly */
    emit(-2.772588722239781);       /* -ln2 * 4 -> exp = 0.0625 exactly */
    emit(-3.4657359027997265);      /* -ln2 * 5 -> exp = 0.03125 exactly */
    emit(1.0e300);                  /* deep overflow -> +Inf */
    emit(-1.0e300);                 /* deep underflow -> 0 */
    emit_u(0x3cb0000000000000ULL);  /* 2^-52: near boundary of exp(x) ~ 1+x */
    emit_u(0xbcb0000000000000ULL);  /* -2^-52 */
    emit_u(0x3c90000000000000ULL);  /* 2^-54: well inside linear region */
    emit_u(0xbc90000000000000ULL);  /* -2^-54 */
    emit(708.3964185322641);        /* ln(DBL_MAX): result near DBL_MAX */
    emit(-708.3964185322641);       /* exp(-ln(DBL_MAX)) = 1/DBL_MAX */
    emit(355.0);                    /* mid-large positive */
    emit(-355.0);                   /* mid-large negative */
}

